module accu(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output valid_out,
    output [9:0] data_out
);

reg [7:0] data_buffer [3:0];
reg [1:0] buffer_index;
reg [9:0] accumulator;
reg valid_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        buffer_index <= 0;
        accumulator <= 0;
        valid_out_reg <= 0;
    end else if (valid_in) begin
        data_buffer[buffer_index] <= data_in;
        buffer_index <= buffer_index + 1;
        if (buffer_index == 2'b11) begin
            accumulator <= {2'b00, data_buffer[0]} + {2'b00, data_buffer[1]} + {2'b00, data_buffer[2]} + {2'b00, data_buffer[3]};
            valid_out_reg <= 1;
        end else begin
            valid_out_reg <= 0;
        end
    end else begin
        valid_out_reg <= 0;
    end
end

assign valid_out = valid_out_reg;
assign data_out = accumulator;

endmodule
